"use client";

import { motion } from "framer-motion";
import {
  type ClusterMode,
  type HeatmapCell,
  GENES,
  PATIENTS,
  valueToColor,
} from "@/lib/cluster-data";

type HeatmapProps = {
  cells: HeatmapCell[];
  mode: ClusterMode;
  contrast: number;
  cellSize?: number;
  showLabels?: boolean;
  compact?: boolean;
};

export function Heatmap({
  cells,
  mode,
  contrast,
  cellSize = 32,
  showLabels = true,
  compact = false,
}: HeatmapProps) {
  const gap = compact ? 2 : 3;
  const labelW = compact ? 28 : 40;
  const labelH = compact ? 18 : 24;

  const rowLabels = [...new Set(cells.map((c) => c.patient))];
  const colLabels = [...new Set(cells.map((c) => c.gene))];

  const gridW = colLabels.length * (cellSize + gap) - gap;
  const gridH = rowLabels.length * (cellSize + gap) - gap;

  const rowClustered = mode === "row";
  const colClustered = mode === "column";

  return (
    <div className="inline-block">
      {showLabels && (
        <div className="flex" style={{ marginLeft: labelW + 8, marginBottom: 6 }}>
          {colLabels.map((gene) => (
            <motion.span
              key={gene}
              layout
              className="text-center font-mono text-[10px] font-medium"
              style={{
                width: cellSize + gap,
                color: colClustered ? "#67e8f9" : "#64748b",
              }}
            >
              {gene}
            </motion.span>
          ))}
        </div>
      )}

      <div className="flex gap-2">
        {showLabels && (
          <div className="flex flex-col" style={{ width: labelW, gap }}>
            {rowLabels.map((patient) => (
              <motion.span
                key={patient}
                layout
                className="flex items-center justify-end pr-1 font-mono text-[10px] font-medium"
                style={{
                  height: cellSize,
                  color: rowClustered ? "#a78bfa" : "#64748b",
                }}
              >
                {patient}
              </motion.span>
            ))}
          </div>
        )}

        <div
          className="relative"
          style={{ width: gridW, height: gridH }}
        >
          {cells.map((cell) => (
            <motion.div
              key={cell.id}
              layout
              layoutId={compact ? undefined : cell.id}
              transition={{
                layout: { type: "spring", stiffness: 350, damping: 30 },
                backgroundColor: { duration: 0.3 },
              }}
              className="absolute rounded-[4px] border border-white/5"
              style={{
                width: cellSize,
                height: cellSize,
                left: cell.col * (cellSize + gap),
                top: cell.row * (cellSize + gap),
                backgroundColor: valueToColor(cell.value, contrast),
              }}
              title={`${cell.patient} × ${cell.gene}: ${cell.value.toFixed(2)}`}
              whileHover={{ scale: 1.15, zIndex: 10 }}
            />
          ))}
        </div>
      </div>

      {showLabels && !compact && (
        <div
          className="mt-3 flex justify-between text-[10px] text-slate-500"
          style={{ width: labelW + 8 + gridW }}
        >
          <span>Rows (patients) →</span>
          <span>↑ Columns (genes)</span>
        </div>
      )}
    </div>
  );
}
