"use client";

import { useMemo, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import {
  type ClusterMode,
  MODE_INFO,
  buildHeatmapCells,
} from "@/lib/cluster-data";
import { Heatmap } from "./Heatmap";

const MODES: ClusterMode[] = ["original", "row", "column"];

function Slider({
  label,
  value,
  min,
  max,
  step,
  onChange,
  format,
}: {
  label: string;
  value: number;
  min: number;
  max: number;
  step: number;
  onChange: (v: number) => void;
  format?: (v: number) => string;
}) {
  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <label className="text-xs font-medium text-slate-400">{label}</label>
        <span className="font-mono text-xs text-cyan-400">
          {format ? format(value) : value.toFixed(2)}
        </span>
      </div>
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={value}
        onChange={(e) => onChange(parseFloat(e.target.value))}
        className="h-1.5 w-full cursor-pointer appearance-none rounded-full bg-slate-700 accent-cyan-400"
      />
    </div>
  );
}

export function ClusteringDashboard() {
  const [mode, setMode] = useState<ClusterMode>("original");
  const [contrast, setContrast] = useState(1.4);
  const [noise, setNoise] = useState(0.04);

  const cells = useMemo(() => buildHeatmapCells(mode, noise), [mode, noise]);
  const info = MODE_INFO[mode];

  const miniModes = MODES.map((m) => ({
    mode: m,
    cells: buildHeatmapCells(m, noise),
    info: MODE_INFO[m],
  }));

  return (
    <div className="min-h-screen bg-[#0b0f17] text-slate-100">
      <div className="pointer-events-none fixed inset-0 bg-[radial-gradient(ellipse_at_top,_rgba(56,189,248,0.08),_transparent_50%),radial-gradient(ellipse_at_bottom_right,_rgba(167,139,250,0.06),_transparent_50%)]" />

      <div className="relative mx-auto max-w-6xl px-6 py-10">
        <header className="mb-10">
          <motion.p
            initial={{ opacity: 0, y: -8 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-2 text-xs font-semibold uppercase tracking-widest text-cyan-400/80"
          >
            Visual Analytics · Exercise 5
          </motion.p>
          <motion.h1
            initial={{ opacity: 0, y: -8 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.05 }}
            className="text-3xl font-semibold tracking-tight text-white"
          >
            One-Direction Clustering
          </motion.h1>
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.1 }}
            className="mt-3 max-w-2xl text-sm leading-relaxed text-slate-400"
          >
            Regular clustering groups data along <strong className="text-slate-200">one axis only</strong> —
            either similar rows (patients) or similar columns (genes), never both at once.
          </motion.p>
        </header>

        <div className="grid gap-6 lg:grid-cols-[280px_1fr]">
          {/* Controls */}
          <motion.aside
            initial={{ opacity: 0, x: -16 }}
            animate={{ opacity: 1, x: 0 }}
            className="space-y-5"
          >
            <div className="rounded-2xl border border-white/8 bg-white/[0.03] p-5 backdrop-blur-sm">
              <h2 className="mb-4 text-xs font-semibold uppercase tracking-wider text-slate-500">
                Clustering mode
              </h2>
              <div className="space-y-2">
                {MODES.map((m) => {
                  const active = mode === m;
                  const meta = MODE_INFO[m];
                  return (
                    <button
                      key={m}
                      onClick={() => setMode(m)}
                      className={`relative w-full rounded-xl px-4 py-3 text-left transition-colors ${
                        active
                          ? "bg-cyan-500/10 text-white"
                          : "bg-transparent text-slate-400 hover:bg-white/5 hover:text-slate-200"
                      }`}
                    >
                      {active && (
                        <motion.div
                          layoutId="mode-highlight"
                          className="absolute inset-0 rounded-xl border border-cyan-400/30"
                          transition={{ type: "spring", stiffness: 400, damping: 30 }}
                        />
                      )}
                      <span className="relative text-sm font-medium">{meta.title}</span>
                      <span className="relative mt-0.5 block text-[11px] text-slate-500">
                        {meta.analogy}
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>

            <div className="rounded-2xl border border-white/8 bg-white/[0.03] p-5 backdrop-blur-sm">
              <h2 className="mb-4 text-xs font-semibold uppercase tracking-wider text-slate-500">
                Adjustments
              </h2>
              <div className="space-y-5">
                <Slider
                  label="Color contrast"
                  value={contrast}
                  min={0.6}
                  max={2.5}
                  step={0.1}
                  onChange={setContrast}
                  format={(v) => `${v.toFixed(1)}×`}
                />
                <Slider
                  label="Data noise"
                  value={noise}
                  min={0}
                  max={0.2}
                  step={0.01}
                  onChange={setNoise}
                  format={(v) => `${(v * 100).toFixed(0)}%`}
                />
              </div>
            </div>

            <AnimatePresence mode="wait">
              <motion.div
                key={mode}
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -8 }}
                className="rounded-2xl border border-white/8 bg-white/[0.03] p-5"
              >
                <h3 className="text-sm font-medium text-white">{info.title}</h3>
                <p className="mt-2 text-xs leading-relaxed text-slate-400">{info.subtitle}</p>
                {info.activeAxis !== "none" && (
                  <div className="mt-3 flex items-center gap-2">
                    <span
                      className={`h-2 w-2 rounded-full ${
                        info.activeAxis === "rows" ? "bg-violet-400" : "bg-cyan-400"
                      }`}
                    />
                    <span className="text-[11px] text-slate-500">
                      {info.activeAxis === "rows"
                        ? "Rows reordered · columns fixed"
                        : "Columns reordered · rows fixed"}
                    </span>
                  </div>
                )}
              </motion.div>
            </AnimatePresence>
          </motion.aside>

          {/* Main heatmap */}
          <motion.main
            initial={{ opacity: 0, y: 16 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="rounded-2xl border border-white/8 bg-white/[0.02] p-8"
          >
            <div className="mb-6 flex items-start justify-between">
              <div>
                <h2 className="text-lg font-medium text-white">Gene expression matrix</h2>
                <p className="mt-1 text-xs text-slate-500">
                  12 patients × 8 genes · synthetic normalized expression (0–1)
                </p>
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500">
                <span className="flex items-center gap-1.5">
                  <span className="h-3 w-3 rounded-sm bg-[rgb(15,23,42)]" /> Low
                </span>
                <span className="flex items-center gap-1.5">
                  <span className="h-3 w-3 rounded-sm bg-[rgb(35,153,242)]" /> High
                </span>
              </div>
            </div>

            <div className="flex justify-center overflow-x-auto py-4">
              <Heatmap cells={cells} mode={mode} contrast={contrast} />
            </div>
          </motion.main>
        </div>

        {/* Comparison row */}
        <section className="mt-8">
          <h2 className="mb-4 text-sm font-medium text-slate-300">Compare all three modes</h2>
          <div className="grid gap-4 md:grid-cols-3">
            {miniModes.map(({ mode: m, cells: c, info: i }) => (
              <motion.button
                key={m}
                onClick={() => setMode(m)}
                whileHover={{ y: -2 }}
                className={`rounded-2xl border p-4 text-left transition-colors ${
                  mode === m
                    ? "border-cyan-400/40 bg-cyan-500/5"
                    : "border-white/8 bg-white/[0.02] hover:border-white/15"
                }`}
              >
                <p className="text-xs font-medium text-slate-300">{i.title}</p>
                <div className="mt-3 flex justify-center">
                  <Heatmap
                    cells={c}
                    mode={m}
                    contrast={contrast}
                    cellSize={18}
                    showLabels={false}
                    compact
                  />
                </div>
              </motion.button>
            ))}
          </div>
        </section>

        {/* Explainer cards */}
        <section className="mt-8 grid gap-4 md:grid-cols-2">
          <motion.div
            animate={{
              borderColor: mode === "row" ? "rgba(167,139,250,0.4)" : "rgba(255,255,255,0.08)",
            }}
            className="rounded-2xl border bg-white/[0.02] p-5"
          >
            <h3 className="text-sm font-medium text-violet-300">Row clustering</h3>
            <p className="mt-2 text-xs leading-relaxed text-slate-400">
              Groups similar <strong className="text-slate-300">patients</strong> and reorders rows.
              Columns stay in place. You see horizontal bands of expression.
            </p>
          </motion.div>
          <motion.div
            animate={{
              borderColor: mode === "column" ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.08)",
            }}
            className="rounded-2xl border bg-white/[0.02] p-5"
          >
            <h3 className="text-sm font-medium text-cyan-300">Column clustering</h3>
            <p className="mt-2 text-xs leading-relaxed text-slate-400">
              Groups similar <strong className="text-slate-300">genes</strong> and reorders columns.
              Rows stay in place. You see vertical bands of co-expression.
            </p>
          </motion.div>
        </section>
      </div>
    </div>
  );
}
